import{_ as o}from"./chunks/config-page.LA-f_I6f.js";import{_ as a}from"./chunks/Screenshot1.DBZ_Glnr.js";import{_ as r,a as e}from"./chunks/Screenshot3.gXrH4m02.js";import{_ as i,o as s,c as l,ag as n}from"./chunks/framework.CvgP6Fyv.js";const k=JSON.parse('{"title":"快速上手","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1776357037000}'),d={name:"guide/getting-started.md"};function g(p,t,h,c,u,m){return s(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">首次使用前请手动备份</p><p>备份你的存档和 Mod 文件夹。本软件经过初步测试，但多一道保险总没错。</p></div><h2 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h2><p>使用 Sync the Spire 之前，你需要准备两样东西：</p><ol><li><strong>一个远程 Git 仓库</strong> — 用于存储和同步 Mod 配置</li><li><strong>Sync the Spire 客户端</strong> — <a href="/guide/installation">下载安装</a></li></ol><h2 id="第一步-准备远程仓库" tabindex="-1">第一步：准备远程仓库 <a class="header-anchor" href="#第一步-准备远程仓库" aria-label="Permalink to &quot;第一步：准备远程仓库&quot;">​</a></h2><p>Sync the Spire 使用 Git 仓库来同步数据，你需要一个远程仓库地址。</p><ul><li><strong>自己建房</strong>：在 Git 托管平台创建一个仓库，然后邀请队友加入</li><li><strong>跟随队友</strong>：直接使用队友提供的仓库地址，跳过创建步骤</li></ul><table tabindex="0"><thead><tr><th>平台</th><th>说明</th><th>创建指南</th></tr></thead><tbody><tr><td><strong>Gitee</strong></td><td>国内访问快，推荐国内用户首选</td><td><a href="/guide/gitee">查看 Gitee 配置指南</a></td></tr><tr><td><strong>GitHub</strong></td><td>全球通用，但国内部分地区访问受限</td><td><a href="/guide/github">查看 GitHub 配置指南</a></td></tr><tr><td>其他平台</td><td>GitLab、Gitea 等理论上均可</td><td>—</td></tr></tbody></table><p>如果你要自己创建仓库，按照对应指南完成仓库创建和认证配置。如果使用队友的仓库地址，可直接跳到下一步。</p><h2 id="第二步-填写配置并初始化" tabindex="-1">第二步：填写配置并初始化 <a class="header-anchor" href="#第二步-填写配置并初始化" aria-label="Permalink to &quot;第二步：填写配置并初始化&quot;">​</a></h2><p>打开 Sync the Spire，你会看到配置页面：</p><p><img src="'+o+'" alt="配置页"></p><ol><li>将仓库地址粘贴到「<strong>远程仓库 URL</strong>」输入框</li><li>填写你的<strong>昵称</strong>（队友会看到这个名字）</li><li>选择<strong>认证方式</strong>（各平台推荐的方式见对应配置指南）</li><li>填写或自动查找<strong>游戏路径</strong>和<strong>存档路径</strong></li><li>点击「<strong>保存并初始化</strong>」</li></ol><div class="tip custom-block"><p class="custom-block-title">找不到路径？</p><ul><li><strong>游戏安装路径</strong>：Steam 中右键游戏 → <strong>管理</strong> → <strong>浏览本地文件</strong></li><li><strong>存档路径</strong>：启动游戏后按 <strong><code>~</code></strong> 键打开控制台，输入 <code>open saves</code> 回车</li></ul></div><p>初始化完成后自动进入主界面，接下来就可以开始使用了。</p><h2 id="第三步-开始使用" tabindex="-1">第三步：开始使用 <a class="header-anchor" href="#第三步-开始使用" aria-label="Permalink to &quot;第三步：开始使用&quot;">​</a></h2><p>配置完成后，根据你的角色选择操作。</p><h3 id="做房主-—-分享-mod-配置" tabindex="-1">做房主 — 分享 Mod 配置 <a class="header-anchor" href="#做房主-—-分享-mod-配置" aria-label="Permalink to &quot;做房主 — 分享 Mod 配置&quot;">​</a></h3><p>你负责维护 Mod 配置，队友从你这里同步。</p><p><img src="'+a+'" alt="主界面"></p><ol><li>在分支名输入框中填入一个名称（简单描述一下这套 Mod 配置），点击「<strong>创建</strong>」</li><li>像平时一样安装、调整 Mods</li><li>完成后点击「<strong>上传</strong>」</li></ol><p>别忘了把仓库地址分享给队友，并在仓库中<a href="/guide/gitee#_3-邀请队友">邀请他们为协作者</a>。</p><blockquote><p>更多细节见 <a href="/guide/host">做房主</a></p></blockquote><h3 id="跟随别人-—-使用房主的配置" tabindex="-1">跟随别人 — 使用房主的配置 <a class="header-anchor" href="#跟随别人-—-使用房主的配置" aria-label="Permalink to &quot;跟随别人 — 使用房主的配置&quot;">​</a></h3><p>你只需要拉取房主分享的配置即可。</p><ol><li><p>点击「<strong>切换分支</strong>」，在列表中选择房主的分支</p><p><img src="'+r+'" alt="分支列表"></p></li><li><p>可预览该分支包含的所有 Mod，确认无误后点击「<strong>同步此分支</strong>」</p><p><img src="'+e+'" alt="Mod 预览"></p></li><li><p>同步完成，直接开游戏即可</p></li></ol><p>之后每次联机前，点击「<strong>拉取</strong>」获取房主的最新配置。</p><blockquote><p>更多细节见 <a href="/guide/join">跟随别人</a></p></blockquote>',29)])])}const S=i(d,[["render",g]]);export{k as __pageData,S as default};
